    "lyricsHtml": "\n  <span class=\"chord\" data-chord=\"G7\">G7</span>                     <span class=\"chord\" data-chord=\"C7\">C7</span>    <span class=\"chord\" data-chord=\"B7\">B7</span>\n<span class=\"lyric-line\">O cérebro eletrônico faz tudo</span>\n          <span class=\"chord\" data-chord=\"Em7\">Em7</span>   <span class=\"chord\" data-chord=\"B7\">B7</span>\n<span class=\"lyric-line\">Faz quase tudo</span>\n          <span class=\"chord\" data-chord=\"C7\">C7</span>   <span class=\"chord\" data-chord=\"C#7\">C#7</span> <span class=\"chord\" data-chord=\"D7\">D7</span>\n<span class=\"lyric-line\">Faz quase tudo</span>\n          <span class=\"chord\" data-chord=\"G7\">G7</span>    <span class=\"chord\" data-chord=\"C7\">C7</span>\n<span class=\"lyric-line\">Mas ele é mudo</span>\n\n  <span class=\"chord\" data-chord=\"G7\">G7</span>                   <span class=\"chord\" data-chord=\"C7\">C7</span>     <span class=\"chord\" data-chord=\"B7\">B7</span>\n<span class=\"lyric-line\">O cérebro eletrônico comanda</span>\n           <span class=\"chord\" data-chord=\"Em7\">Em7</span>   <span class=\"chord\" data-chord=\"B7\">B7</span>\n<span class=\"lyric-line\">Manda e desmanda</span>\n           <span class=\"chord\" data-chord=\"C7\">C7</span>    <span class=\"chord\" data-chord=\"C#7\">C#7</span> <span class=\"chord\" data-chord=\"D7\">D7</span>\n<span class=\"lyric-line\">Ele é quem manda</span>\n            <span class=\"chord\" data-chord=\"G7\">G7</span>    <span class=\"chord\" data-chord=\"C7\">C7</span>\n<span class=\"lyric-line\">Mas ele não anda</span>\n\n   <span class=\"chord\" data-chord=\"Em7\">Em7</span>         <span class=\"chord\" data-chord=\"A7\">A7</span>\n<span class=\"lyric-line\">Só eu posso pensar</span>\n         <span class=\"chord\" data-chord=\"Em7\">Em7</span>\n<span class=\"lyric-line\">Se Deus existe</span>\n   <span class=\"chord\" data-chord=\"B7\">B7</span>\n<span class=\"lyric-line\">Só eu</span>\n   <span class=\"chord\" data-chord=\"Em7\">Em7</span>         <span class=\"chord\" data-chord=\"A7\">A7</span>\n<span class=\"lyric-line\">Só eu posso chorar</span>\n             <span class=\"chord\" data-chord=\"Em7\">Em7</span>\n<span class=\"lyric-line\">Quando estou triste</span>\n   <span class=\"chord\" data-chord=\"D7\">D7</span>\n<span class=\"lyric-line\">Só eu</span>\n\n   <span class=\"chord\" data-chord=\"G7\">G7</span>            <span class=\"chord\" data-chord=\"C7\">C7</span>\n<span class=\"lyric-line\">Eu cá com meus botões</span>\n           <span class=\"chord\" data-chord=\"G7\">G7</span>    <span class=\"chord\" data-chord=\"C7\">C7</span>\n<span class=\"lyric-line\">De carne e osso  Hum</span>\n          <span class=\"chord\" data-chord=\"G7\">G7</span>    <span class=\"chord\" data-chord=\"B7\">B7</span>\n<span class=\"lyric-line\">Eu falo e ouço  Hum</span>\n           <span class=\"chord\" data-chord=\"Em7\">Em7</span>   <span class=\"chord\" data-chord=\"B7\">B7</span>\n<span class=\"lyric-line\">Eu penso e posso</span>\n\n   <span class=\"chord\" data-chord=\"Em7\">Em7</span>       <span class=\"chord\" data-chord=\"A7\">A7</span>\n<span class=\"lyric-line\">Eu posso decidir</span>\n           <span class=\"chord\" data-chord=\"Em7\">Em7</span>      <span class=\"chord\" data-chord=\"B7\">B7</span>\n<span class=\"lyric-line\">Se vivo ou morro porque</span>\n   <span class=\"chord\" data-chord=\"Em7\">Em7</span>\n<span class=\"lyric-line\">Porque sou vivo</span>\n<span class=\"chord\" data-chord=\"B7\">B7</span>         <span class=\"chord\" data-chord=\"Em7\">Em7</span>      <span class=\"chord\" data-chord=\"D7\">D7</span>\n<span class=\"lyric-line\">Vivo pra cachorro e sei</span>\n\n    <span class=\"chord\" data-chord=\"G7\">G7</span>         <span class=\"chord\" data-chord=\"C7\">C7</span>        <span class=\"chord\" data-chord=\"G7\">G7</span>           <span class=\"chord\" data-chord=\"C7\">C7</span>\n<span class=\"lyric-line\">Que cérebro eletrônico nenhum me dá socorro</span>\n         <span class=\"chord\" data-chord=\"G7\">G7</span>         <span class=\"chord\" data-chord=\"B7\">B7</span>           <span class=\"chord\" data-chord=\"Em7\">Em7</span>   <span class=\"chord\" data-chord=\"B7\">B7</span>\n<span class=\"lyric-line\">No meu caminho inevitável para a morte</span>\n\n   <span class=\"chord\" data-chord=\"Em7\">Em7</span>         <span class=\"chord\" data-chord=\"B7\">B7</span>\n<span class=\"lyric-line\">Porque sou vivo</span>\n          <span class=\"chord\" data-chord=\"Em7\">Em7</span>    <span class=\"chord\" data-chord=\"B7\">B7</span>\n<span class=\"lyric-line\">Sou muito vivo e sei</span>\n      <span class=\"chord\" data-chord=\"Em7\">Em7</span>             <span class=\"chord\" data-chord=\"B7\">B7</span>         <span class=\"chord\" data-chord=\"Em7\">Em7</span>    <span class=\"chord\" data-chord=\"D7\">D7</span>\n<span class=\"lyric-line\">Que a morte é nosso impulso primitivo e sei</span>\n\n    <span class=\"chord\" data-chord=\"G7\">G7</span>         <span class=\"chord\" data-chord=\"C7\">C7</span>        <span class=\"chord\" data-chord=\"G7\">G7</span>           <span class=\"chord\" data-chord=\"C7\">C7</span>\n<span class=\"lyric-line\">Que cérebro eletrônico nenhum me dá socorro</span>\n           <span class=\"chord\" data-chord=\"G7\">G7</span>              <span class=\"chord\" data-chord=\"B7\">B7</span>\n<span class=\"lyric-line\">Com seus botões de ferro e seus</span>\n         <span class=\"chord\" data-chord=\"Em7\">Em7</span>    <span class=\"chord\" data-chord=\"D7\">D7</span>\n<span class=\"lyric-line\">Olhos de vidro</span>\n",
